CREATE TABLE IF NOT EXISTS teams (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), course_id UUID NOT NULL REFERENCES courses(id), name TEXT NOT NULL, created_by UUID REFERENCES profiles(id), created_at TIMESTAMPTZ DEFAULT now()); ALTER TABLE teams ENABLE ROW LEVEL SECURITY; CREATE TABLE IF NOT EXISTS team_members (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), team_id UUID NOT NULL REFERENCES teams(id) ON DELETE CASCADE, student_id UUID NOT NULL REFERENCES profiles(id), joined_at TIMESTAMPTZ DEFAULT now(), UNIQUE(team_id, student_id)); ALTER TABLE team_members ENABLE ROW LEVEL SECURITY; CREATE TABLE IF NOT EXISTS social_challenges (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), course_id UUID REFERENCES courses(id), title TEXT NOT NULL, description TEXT, challenge_type TEXT NOT NULL DEFAULT 'course' CHECK (challenge_type IN ('team','course','individual','peer')), goal_metric TEXT NOT NULL, goal_target NUMERIC NOT NULL DEFAULT 0, start_date TIMESTAMPTZ NOT NULL, end_date TIMESTAMPTZ NOT NULL, status TEXT NOT NULL DEFAULT 'active' CHECK (status IN ('draft','active','completed','cancelled')), created_by UUID REFERENCES profiles(id), created_at TIMESTAMPTZ DEFAULT now()); ALTER TABLE social_challenges ENABLE ROW LEVEL SECURITY; CREATE TABLE IF NOT EXISTS challenge_progress (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), challenge_id UUID NOT NULL REFERENCES social_challenges(id) ON DELETE CASCADE, participant_id UUID NOT NULL REFERENCES profiles(id), team_id UUID REFERENCES teams(id), current_value NUMERIC NOT NULL DEFAULT 0, completed_at TIMESTAMPTZ, updated_at TIMESTAMPTZ DEFAULT now(), UNIQUE(challenge_id, participant_id)); ALTER TABLE challenge_progress ENABLE ROW LEVEL SECURITY; ALTER TABLE xp_transactions ADD COLUMN IF NOT EXISTS team_id UUID REFERENCES teams(id); ALTER TABLE badges ADD COLUMN IF NOT EXISTS team_id UUID REFERENCES teams(id); ALTER TABLE badges ADD COLUMN IF NOT EXISTS tier TEXT CHECK (tier IN ('bronze','silver','gold')); ALTER TABLE student_gamification ADD COLUMN IF NOT EXISTS comeback_active BOOLEAN DEFAULT false; ALTER TABLE student_gamification ADD COLUMN IF NOT EXISTS comeback_days_completed INTEGER DEFAULT 0; ALTER TABLE student_gamification ADD COLUMN IF NOT EXISTS comeback_streak_to_restore INTEGER DEFAULT 0; ALTER TABLE student_gamification ADD COLUMN IF NOT EXISTS habit_difficulty_level TEXT DEFAULT 'starter' CHECK (habit_difficulty_level IN ('starter','intermediate','advanced','master')); ALTER TABLE student_gamification ADD COLUMN IF NOT EXISTS habit_level_streak INTEGER DEFAULT 0; CREATE POLICY "teams_select" ON teams FOR SELECT TO authenticated USING (true); CREATE POLICY "teams_insert" ON teams FOR INSERT TO authenticated WITH CHECK (true); CREATE POLICY "team_members_select" ON team_members FOR SELECT TO authenticated USING (true); CREATE POLICY "team_members_insert" ON team_members FOR INSERT TO authenticated WITH CHECK (true); CREATE POLICY "social_challenges_select" ON social_challenges FOR SELECT TO authenticated USING (true); CREATE POLICY "social_challenges_insert" ON social_challenges FOR INSERT TO authenticated WITH CHECK (true); CREATE POLICY "challenge_progress_select" ON challenge_progress FOR SELECT TO authenticated USING (true); CREATE POLICY "challenge_progress_upsert" ON challenge_progress FOR INSERT TO authenticated WITH CHECK (true); CREATE POLICY "challenge_progress_update" ON challenge_progress FOR UPDATE TO authenticated USING (participant_id = auth.uid());;
